scripts.script:
// Shared by the vanilla-js, React and Vue builds. One dataset, drawn two ways:
// a column chart (magnitude per bar) and a unit chart (one dot per seat). The
// morph feature (bundled) makes the bar burst into its dots on the switch.
var LABELS = ['Republican', 'Democrat', 'Independent']
var COLORS = ['#EB4D4B', '#2E86DE', '#95A5A6']
var VALUES = [276, 266, 3]

function setActive(view) {
  document.querySelectorAll('.actions button[data-view]').forEach(function (btn) {
    btn.classList.toggle('active', btn.getAttribute('data-view') === view)
  })
}

chart.options:
chart: {
  id: 'explodeChart',
  type: 'bar',
  height: 420,
  toolbar: {
    show: false
  },
  animations: {
    enabled: true,
    speed: 900,
    chartTypeMorph: {
      enabled: true,
      speed: 900,
    },
  },
},
labels: ['Republican', 'Democrat', 'Independent'],
colors: ['#EB4D4B', '#2E86DE', '#95A5A6'],
legend: { show: false },
dataLabels: { enabled: false },
plotOptions: {
  bar: {
    distributed: true,
    borderRadius: 4,
    columnWidth: '55%',
  },
  unit: {
    layout: 'grouped',
    clusterLabels: { show: true },
  },
},
grid: { show: false },
yaxis: { show: false },
xaxis: {
  categories: ['Republican', 'Democrat', 'Independent'],
  axisBorder: { show: false },
  axisTicks: { show: false },
},

vanilla-js-script:
// LABELS, COLORS, VALUES and setActive live in the shared head script.
var current = 'bar'
setActive(current)

document.querySelectorAll('.actions button[data-view]').forEach(function (btn) {
  btn.addEventListener('click', function () {
    var view = btn.getAttribute('data-view')
    if (view === current) return
    current = view
    setActive(current)
    if (view === 'unit') {
      chart.updateOptions({
        chart: { type: 'unit' },
        series: VALUES,
        labels: LABELS,
      })
    } else {
      chart.updateOptions({
        chart: { type: 'bar' },
        series: [{ name: 'Seats', data: VALUES }],
        labels: LABELS,
      })
    }
  })
})

react-script:
React.useEffect(() => {
  // Reach the live instance by its chart.id, then wire the controls. (LABELS,
  // COLORS, VALUES and setActive live in the shared head script.)
  let chart
  let current = 'bar'

  const timer = window.setInterval(() => {
    chart = ApexCharts.getChartByID('explodeChart')
    if (!chart) return
    window.clearInterval(timer)

    setActive(current)

    document.querySelectorAll('.actions button[data-view]').forEach((btn) => {
      btn.addEventListener('click', () => {
        const view = btn.getAttribute('data-view')
        if (view === current) return
        current = view
        setActive(current)
        if (view === 'unit') {
          chart.updateOptions({ chart: { type: 'unit' }, series: VALUES, labels: LABELS })
        } else {
          chart.updateOptions({ chart: { type: 'bar' }, series: [{ name: 'Seats', data: VALUES }], labels: LABELS })
        }
      })
    })
  }, 50)

  return () => window.clearInterval(timer)
}, [])

vue-script:
mounted: function () {
  // Reach the live instance by its chart.id, then wire the controls. (LABELS,
  // COLORS, VALUES and setActive live in the shared head script.)
  var me = this
  var current = 'bar'

  me.explodeTimer = window.setInterval(function () {
    var chart = ApexCharts.getChartByID('explodeChart')
    if (!chart) return
    window.clearInterval(me.explodeTimer)

    setActive(current)

    document.querySelectorAll('.actions button[data-view]').forEach(function (btn) {
      btn.addEventListener('click', function () {
        var view = btn.getAttribute('data-view')
        if (view === current) return
        current = view
        setActive(current)
        if (view === 'unit') {
          chart.updateOptions({ chart: { type: 'unit' }, series: VALUES, labels: LABELS })
        } else {
          chart.updateOptions({ chart: { type: 'bar' }, series: [{ name: 'Seats', data: VALUES }], labels: LABELS })
        }
      })
    })
  }, 50)
},
beforeDestroy: function () {
  window.clearInterval(this.explodeTimer)
},
